Server Guide
The mcpServer { } computation expression
Every FsMcp server starts with the mcpServer CE. It collects your configuration and produces a validated ServerConfig:
open FsMcp.Core
open FsMcp.Server

let server = mcpServer {
    name &quot;MyServer&quot;           // required -- ServerName (non-empty)
    version &quot;1.0.0&quot;           // required -- ServerVersion (non-empty)
    tool myToolDefinition     // zero or more tools
    resource myResource       // zero or more resources
    prompt myPrompt           // zero or more prompts
    middleware myMiddleware    // zero or more middleware
    useStdio                  // transport (default is stdio)
}

Missing name or version raises FsMcpConfigException with a message telling you exactly what to add. Duplicate tool names, resource URIs, or prompt names also raise FsMcpConfigException.
Untyped tools with Tool.define
For simple tools where you parse arguments manually from Map&lt;string, JsonElement&gt;:
open System.Text.Json
open FsMcp.Core
open FsMcp.Server

let echoTool =
    Tool.define &quot;echo&quot; &quot;Echoes the message back&quot; (fun args -&gt;
        let msg =
            args
            |&gt; Map.tryFind &quot;message&quot;
            |&gt; Option.map (fun j -&gt; j.GetString())
            |&gt; Option.defaultValue &quot;(no message)&quot;
        task { return Ok [ Content.text $&quot;Echo: {msg}&quot; ] })
    |&gt; unwrapResult

Tool.define returns Result&lt;ToolDefinition, ValidationError&gt;. Use unwrapResult to extract the value or fail with a descriptive error.
The handler signature is:
Map&lt;string, JsonElement&gt; -&gt; Task&lt;Result&lt;Content list, McpError&gt;&gt;

Typed tools with TypedTool.define&lt;'T&gt;
Define an F# record for your input. TypeShape inspects it at startup and generates a JSON Schema automatically. Option fields become optional in the schema:
type ReverseArgs = { text: string; uppercase: bool option }

let reverseTool =
    TypedTool.define&lt;ReverseArgs&gt; &quot;reverse&quot; &quot;Reverses the text&quot; (fun args -&gt; task {
        let reversed = args.text |&gt; Seq.rev |&gt; System.String.Concat
        let result =
            if args.uppercase |&gt; Option.defaultValue false
            then reversed.ToUpper()
            else reversed
        return Ok [ Content.text result ]
    }) |&gt; unwrapResult

The generated schema has text as required and uppercase as optional (not in the required array, nullable). The handler receives a deserialized ReverseArgs directly -- no manual JSON parsing.
The mcpTool { } nested CE
For more control over tool construction, use the nested mcpTool CE:
let myTool = mcpTool {
    toolName &quot;calculate&quot;
    description &quot;Performs a calculation&quot;
    handler (fun args -&gt; task {
        let a = args |&gt; Map.tryFind &quot;a&quot; |&gt; Option.map (fun j -&gt; j.GetDouble()) |&gt; Option.defaultValue 0.0
        let b = args |&gt; Map.tryFind &quot;b&quot; |&gt; Option.map (fun j -&gt; j.GetDouble()) |&gt; Option.defaultValue 0.0
        return Ok [ Content.text $&quot;{a + b}&quot; ]
    })
}

For typed handlers with the mcpTool CE, use TypedHandler.create&lt;'T&gt;:
type CalcArgs = { a: float; b: float }

let typedCalcTool = mcpTool {
    toolName &quot;add&quot;
    description &quot;Add two numbers&quot;
    typedHandler (TypedHandler.create&lt;CalcArgs&gt; (fun args -&gt; task {
        return Ok [ Content.text $&quot;{args.a + args.b}&quot; ]
    }))
}

TypedHandler.create&lt;'T&gt; returns a TypedHandlerInfo with the raw handler and the auto-generated schema. The typedHandler operation wires both into the tool definition.
Resources with Resource.define
Resources expose data that clients can read. The handler receives Map&lt;string, string&gt;:
open FsMcp.Core.Validation

let statusResource =
    Resource.define &quot;info://server/status&quot; &quot;Server Status&quot; (fun _ -&gt; task {
        let uri = ResourceUri.create &quot;info://server/status&quot; |&gt; unwrapResult
        let mime = MimeType.create &quot;application/json&quot; |&gt; unwrapResult
        return Ok (TextResource (uri, mime, &quot;&quot;&quot;{&quot;status&quot;:&quot;running&quot;}&quot;&quot;&quot;))
    }) |&gt; unwrapResult

Resource URIs must be absolute with a scheme (e.g., https://, file:///, info://).
Typed resources with TypedResource.define&lt;'T&gt;
type FileArgs = { path: string }

let fileResource =
    TypedResource.define&lt;FileArgs&gt; &quot;file:///docs&quot; &quot;Documentation files&quot; (fun args -&gt; task {
        let uri = ResourceUri.create $&quot;file:///{args.path}&quot; |&gt; unwrapResult
        let mime = MimeType.create &quot;text/plain&quot; |&gt; unwrapResult
        let! content = System.IO.File.ReadAllTextAsync(args.path)
        return Ok (TextResource (uri, mime, content))
    }) |&gt; unwrapResult

Prompts with Prompt.define
Prompts define reusable conversation templates:
let summarizePrompt =
    Prompt.define &quot;summarize&quot;
        [ { Name = &quot;topic&quot;; Description = Some &quot;The topic to summarize&quot;; Required = true } ]
        (fun args -&gt; task {
            let topic = args |&gt; Map.tryFind &quot;topic&quot; |&gt; Option.defaultValue &quot;unknown&quot;
            return Ok [
                { Role = User; Content = Content.text $&quot;Please summarize {topic}.&quot; }
                { Role = Assistant; Content = Content.text $&quot;Here is a summary of {topic}.&quot; }
            ]
        })
    |&gt; unwrapResult

Typed prompts with TypedPrompt.define&lt;'T&gt;
Arguments are inferred from the record. Option fields become non-required prompt arguments:
type SummarizeArgs = { topic: string; style: string option }

let typedSummarize =
    TypedPrompt.define&lt;SummarizeArgs&gt; &quot;summarize&quot; &quot;Summarize a topic&quot; (fun args -&gt; task {
        let style = args.style |&gt; Option.defaultValue &quot;concise&quot;
        return Ok [
            { Role = User; Content = Content.text $&quot;Summarize {args.topic} in a {style} style.&quot; }
        ]
    }) |&gt; unwrapResult

Running the server
Stdio transport (default)
[&lt;EntryPoint&gt;]
let main _ =
    Server.run server |&gt; fun t -&gt; t.GetAwaiter().GetResult()
    0

Or with Async:
[&lt;EntryPoint&gt;]
let main _ =
    Server.runAsync server |&gt; Async.RunSynchronously
    0

HTTP transport
Install the HTTP package:
dotnet add package FsMcp.Server.Http

open FsMcp.Server.Http

[&lt;EntryPoint&gt;]
let main _ =
    HttpServer.run server (Some &quot;/mcp&quot;) &quot;http://localhost:5000&quot;
    |&gt; fun t -&gt; t.GetAwaiter().GetResult()
    0

HttpServer.run takes the ServerConfig, an optional route endpoint (defaults to "/"), and the URL to listen on. It uses ASP.NET Core with Streamable HTTP + SSE.
Full example combining everything
open FsMcp.Core
open FsMcp.Core.Validation
open FsMcp.Server

type CalcArgs = { a: float; b: float }
type EchoArgs = { message: string }

let server = mcpServer {
    name &quot;DemoServer&quot;
    version &quot;1.0.0&quot;

    tool (TypedTool.define&lt;CalcArgs&gt; &quot;add&quot; &quot;Add two numbers&quot; (fun args -&gt; task {
        return Ok [ Content.text $&quot;{args.a + args.b}&quot; ]
    }) |&gt; unwrapResult)

    tool (TypedTool.define&lt;EchoArgs&gt; &quot;echo&quot; &quot;Echo a message&quot; (fun args -&gt; task {
        return Ok [ Content.text $&quot;Echo: {args.message}&quot; ]
    }) |&gt; unwrapResult)

    resource (
        Resource.define &quot;info://demo/version&quot; &quot;Version Info&quot; (fun _ -&gt; task {
            let uri = ResourceUri.create &quot;info://demo/version&quot; |&gt; unwrapResult
            let mime = MimeType.create &quot;text/plain&quot; |&gt; unwrapResult
            return Ok (TextResource (uri, mime, &quot;1.0.0&quot;))
        }) |&gt; unwrapResult)

    prompt (
        Prompt.define &quot;explain&quot;
            [ { Name = &quot;topic&quot;; Description = Some &quot;Topic to explain&quot;; Required = true } ]
            (fun args -&gt; task {
                let topic = args |&gt; Map.tryFind &quot;topic&quot; |&gt; Option.defaultValue &quot;something&quot;
                return Ok [
                    { Role = User; Content = Content.text $&quot;Explain {topic} simply.&quot; }
                ]
            })
        |&gt; unwrapResult)

    useStdio
}

[&lt;EntryPoint&gt;]
let main _ =
    Server.run server |&gt; fun t -&gt; t.GetAwaiter().GetResult()
    0

Middleware Guide
What is McpMiddleware?
type McpMiddleware =
    McpContext -&gt; (McpContext -&gt; Task&lt;McpResponse&gt;) -&gt; Task&lt;McpResponse&gt;

A middleware is a function that receives:

*McpContext* -- the current request context with Method (e.g., "tools/call"), optional Params (a JsonElement), and a CancellationToken.
*next* -- a function to call the next handler (or middleware) in the chain.

It returns a Task&lt;McpResponse&gt; where McpResponse is either Success of JsonElement or McpResponseError of McpError.
The middleware can inspect or modify the context before calling next, inspect or modify the response after, or short-circuit by returning a response without calling next.
Writing a logging middleware
open System.Threading.Tasks
open FsMcp.Core
open FsMcp.Server

let loggingMiddleware (log: ResizeArray&lt;string&gt;) : McpMiddleware =
    fun ctx next -&gt; task {
        log.Add $&quot;[LOG] {ctx.Method} started&quot;
        let! response = next ctx
        let status =
            match response with
            | Success _ -&gt; &quot;OK&quot;
            | McpResponseError _ -&gt; &quot;ERROR&quot;
        log.Add $&quot;[LOG] {ctx.Method} completed: {status}&quot;
        return response
    }

This middleware wraps every request with before/after logging. It always calls next -- it never short-circuits.
Writing an auth middleware
let authMiddleware (allowedMethods: Set&lt;string&gt;) : McpMiddleware =
    fun ctx next -&gt;
        if allowedMethods.Contains ctx.Method then
            next ctx
        else
            Task.FromResult(McpResponseError (TransportError $&quot;Unauthorized: {ctx.Method}&quot;))

This middleware short-circuits: if the method is not in the allowed set, it returns an error immediately without calling next.
Middleware.compose and Middleware.pipeline
Compose two middleware
Middleware.compose chains two middleware so the first runs before the second:
let combined = Middleware.compose (loggingMiddleware log) (authMiddleware allowed)

Execution order: logging wraps auth wraps the handler.
Compose a list into a pipeline
Middleware.pipeline reduces a list of middleware into a single middleware. An empty list returns a pass-through:
let pipeline = Middleware.pipeline [
    loggingMiddleware log
    authMiddleware (Set.ofList [&quot;tools/call&quot;; &quot;tools/list&quot;])
    timingMiddleware timings
]

Execution flows left-to-right: logging -&gt; auth -&gt; timing -&gt; handler -&gt; timing -&gt; auth -&gt; logging.
ValidationMiddleware.create
The built-in validation middleware checks that tool call arguments include all required fields from the tool's JSON Schema before the handler runs. It only applies to tools/call requests against tools that have an InputSchema:
open FsMcp.Server

let server = mcpServer {
    name &quot;ValidatedServer&quot;
    version &quot;1.0.0&quot;

    tool (TypedTool.define&lt;CalcArgs&gt; &quot;add&quot; &quot;Add two numbers&quot; (fun args -&gt; task {
        return Ok [ Content.text $&quot;{args.a + args.b}&quot; ]
    }) |&gt; unwrapResult)

    useStdio
}

// Create validation middleware from the config
let validationMw = ValidationMiddleware.create server

If a required field is missing, the middleware returns McpResponseError (TransportError "Validation failed: Missing required fields: a, b") without ever calling the handler.
Telemetry.tracing() and MetricsCollector
Tracing middleware
Telemetry.tracing() creates a middleware that emits a System.Diagnostics.Activity (span) for each request. Compatible with OpenTelemetry, Application Insights, and any ActivityListener:
open FsMcp.Server

let tracingMw = Telemetry.tracing ()

Tags emitted: mcp.method, mcp.status ("ok" or "error"), mcp.duration_ms, and mcp.error (on exceptions).
MetricsCollector
MetricsCollector tracks request counts and average durations per method:
let collector = Telemetry.MetricsCollector()

// Use collector.Middleware in your pipeline
let metricsMw = collector.Middleware

// Later, query metrics:
let counts = collector.RequestCounts      // Map&lt;string, int&gt;
let avgDurations = collector.AverageDurations  // Map&lt;string, float&gt;

The collector keeps only the last 1000 durations per method to prevent memory leaks. You can customize this:
let collector = Telemetry.MetricsCollector(maxDurationsPerMethod = 500)

Combined tracing + metrics
let allTelemetry = Telemetry.all ()

This composes tracing() and a MetricsCollector into a single middleware.
Composing everything in mcpServer { }
open FsMcp.Core
open FsMcp.Server

type CalcArgs = { a: float; b: float }

let log = ResizeArray&lt;string&gt;()

let server = mcpServer {
    name &quot;FullServer&quot;
    version &quot;1.0.0&quot;

    tool (TypedTool.define&lt;CalcArgs&gt; &quot;add&quot; &quot;Add two numbers&quot; (fun args -&gt; task {
        return Ok [ Content.text $&quot;{args.a + args.b}&quot; ]
    }) |&gt; unwrapResult)

    middleware (Telemetry.tracing ())

    middleware (fun ctx next -&gt; task {
        log.Add $&quot;[LOG] {ctx.Method}&quot;
        return! next ctx
    })

    useStdio
}

// Add validation after building (needs the config to inspect schemas):
let validatedServer =
    { server with
        Middleware = server.Middleware @ [ ValidationMiddleware.create server ] }

Middleware runs in the order they are added. Each middleware call appends to the list. At runtime the pipeline is: first middleware wraps second wraps third wraps the actual handler.

Advanced
StreamingTool.define -- IAsyncEnumerable&lt;Content&gt; handlers
Streaming tools yield content items one at a time via IAsyncEnumerable&lt;Content&gt;. Items are collected and returned as a Content list when the enumeration completes:
open System.Collections.Generic
open System.Runtime.CompilerServices
open FsMcp.Core
open FsMcp.Server

let streamTool =
    StreamingTool.define &quot;count&quot; &quot;Count to N&quot; (fun args -&gt;
        let n =
            args
            |&gt; Map.tryFind &quot;n&quot;
            |&gt; Option.map (fun j -&gt; j.GetInt32())
            |&gt; Option.defaultValue 5
        { new IAsyncEnumerable&lt;Content&gt; with
            member _.GetAsyncEnumerator(_) =
                let mutable i = 0
                { new IAsyncEnumerator&lt;Content&gt; with
                    member _.Current = Content.text $&quot;Count: {i}&quot;
                    member _.MoveNextAsync() =
                        i &lt;- i + 1
                        System.Threading.Tasks.ValueTask&lt;bool&gt;(i &lt;= n)
                    member _.DisposeAsync() =
                        System.Threading.Tasks.ValueTask() } })
    |&gt; unwrapResult

Typed streaming tools
StreamingTool.defineTyped&lt;'T&gt; combines typed input with streaming output:
type CountArgs = { n: int }

let typedStreamTool =
    StreamingTool.defineTyped&lt;CountArgs&gt; &quot;count&quot; &quot;Count to N&quot; (fun args -&gt;
        { new IAsyncEnumerable&lt;Content&gt; with
            member _.GetAsyncEnumerator(_) =
                let mutable i = 0
                { new IAsyncEnumerator&lt;Content&gt; with
                    member _.Current = Content.text $&quot;Count: {i}&quot;
                    member _.MoveNextAsync() =
                        i &lt;- i + 1
                        System.Threading.Tasks.ValueTask&lt;bool&gt;(i &lt;= args.n)
                    member _.DisposeAsync() =
                        System.Threading.Tasks.ValueTask() } })
    |&gt; unwrapResult

ContextualTool.define -- handlers with progress/log notifications
Contextual tools receive a HandlerContext that lets them send progress and log notifications to the client during execution:
open FsMcp.Core
open FsMcp.Server
open FsMcp.Server.Notifications

type ProcessArgs = { data: string }

let contextualToolResult =
    ContextualTool.define&lt;ProcessArgs&gt; &quot;process&quot; &quot;Process data with progress&quot; (fun ctx args -&gt; task {
        do! ctx.Log { Level = Info; Message = &quot;Starting processing&quot;; Logger = Some &quot;process&quot; }

        do! ctx.ReportProgress { Progress = 0.0; Message = Some &quot;Initializing&quot; }
        // ... do work ...
        do! ctx.ReportProgress { Progress = 0.5; Message = Some &quot;Halfway done&quot; }
        // ... do more work ...
        do! ctx.ReportProgress { Progress = 1.0; Message = Some &quot;Complete&quot; }

        do! ctx.Log { Level = Info; Message = &quot;Processing complete&quot;; Logger = Some &quot;process&quot; }

        return Ok [ Content.text $&quot;Processed: {args.data}&quot; ]
    })

ContextualTool.define returns Result&lt;ContextualToolHandle, ValidationError&gt;. The ContextualToolHandle contains:

*Definition* -- the ToolDefinition to register with the server (uses a no-op context by default)
*InvokeWithContext* -- invoke the handler with a specific HandlerContext (for testing or runtime wiring)

Register the tool in the server:
let handle = contextualToolResult |&gt; unwrapResult

let server = mcpServer {
    name &quot;ContextServer&quot;
    version &quot;1.0.0&quot;
    tool handle.Definition
    useStdio
}

Test with a custom context:
let testCtx = HandlerContext.noOp  // progress/log are no-ops

let result =
    ContextualTool.invokeWithContext testCtx handle (Map.ofList [
        &quot;data&quot;, System.Text.Json.JsonDocument.Parse(&quot;\&quot;test\&quot;&quot;).RootElement
    ])
    |&gt; Async.AwaitTask |&gt; Async.RunSynchronously

Notification types
type ProgressUpdate = {
    Progress: float       // 0.0 to 1.0
    Message: string option
}

type McpLogLevel = Debug | Info | Warning | Error

type LogEntry = {
    Level: McpLogLevel
    Message: string
    Logger: string option
}

DynamicServer -- add/remove tools at runtime
DynamicServer wraps a ServerConfig and supports hot-reloading tools:
open FsMcp.Core
open FsMcp.Core.Validation
open FsMcp.Server

let initialConfig = mcpServer {
    name &quot;DynamicDemo&quot;
    version &quot;1.0.0&quot;
    useStdio
}

let dynServer = DynamicServer.create initialConfig

// Add a tool at runtime
let newTool =
    Tool.define &quot;hello&quot; &quot;Says hello&quot; (fun _ -&gt; task {
        return Ok [ Content.text &quot;Hello!&quot; ]
    }) |&gt; unwrapResult

DynamicServer.addTool newTool dynServer

// Check tool count
let count = DynamicServer.toolCount dynServer  // 1

// Subscribe to changes
DynamicServer.onToolsChanged dynServer
|&gt; Event.add (fun () -&gt; printfn &quot;Tools changed!&quot;)

// Remove a tool
let toolName = ToolName.create &quot;hello&quot; |&gt; unwrapResult
DynamicServer.removeTool toolName dynServer

addTool raises FsMcpConfigException if a tool with the same name already exists. Call removeTool first to replace a tool.
SamplingTool.define -- invoke client LLM from server
The FsMcp.Sampling package lets server-side tools ask the client's LLM to generate text:
dotnet add package FsMcp.Sampling

open FsMcp.Core
open FsMcp.Sampling

type SummarizeArgs = { text: string }

let summarizeTool =
    SamplingTool.define&lt;SummarizeArgs&gt; &quot;ai_summarize&quot; &quot;Summarize text using the client LLM&quot;
        (fun ctx args -&gt; task {
            let request =
                SamplingRequest.simple $&quot;Summarize this text:\n\n{args.text}&quot; 200
                |&gt; SamplingRequest.withTemperature 0.3

            let! result = ctx.Sample request
            match result with
            | Ok samplingResult -&gt;
                match samplingResult.Message.Content with
                | Text t -&gt; return Ok [ Content.text t ]
                | _ -&gt; return Ok [ Content.text &quot;[non-text response]&quot; ]
            | Error SamplingNotSupported -&gt;
                return Error (TransportError &quot;Client does not support sampling&quot;)
            | Error (SamplingFailed msg) -&gt;
                return Error (TransportError $&quot;Sampling failed: {msg}&quot;)
            | Error SamplingTimeout -&gt;
                return Error (TransportError &quot;Sampling timed out&quot;)
            | Error (SamplingRejected reason) -&gt;
                return Error (TransportError $&quot;Sampling rejected: {reason}&quot;)
        })
    |&gt; unwrapResult

SamplingRequest builders
// Simple request with one user message
let req = SamplingRequest.simple &quot;What is 2+2?&quot; 100

// With a system prompt
let req2 = SamplingRequest.withSystem &quot;You are a math tutor&quot; &quot;What is 2+2?&quot; 100

// Pipeline style
let req3 =
    SamplingRequest.simple &quot;Explain MCP&quot; 500
    |&gt; SamplingRequest.withTemperature 0.7
    |&gt; SamplingRequest.withModel &quot;claude-sonnet&quot;
    |&gt; SamplingRequest.withStopSequences [ &quot;---&quot; ]

Testing sampling tools
Use SamplingTool.mockContext to provide a fixed response without a real LLM:
let mockCtx = SamplingTool.mockContext &quot;This is a summary.&quot;
// or
let noOpCtx = SamplingTool.noOpContext ()  // always returns SamplingNotSupported

TypeShape caching internals
TypeShape reflection is used to generate JSON Schemas from F# records. Both schema generation and option-field detection are cached per-type in ConcurrentDictionary instances inside the SchemaGen module:

*optionFieldsCache* -- maps Type to the Set&lt;string&gt; of field names that are option types
*schemaCache* -- maps Type to the generated JsonElement schema

This means the first call to TypedTool.define&lt;'T&gt; pays the reflection cost; subsequent calls for the same 'T return instantly. Schemas are generated once at startup and never recomputed.
The schema generation marks F# option fields as not-required (removed from the required array) and nullable, matching what MCP clients expect.
FsMcpConfigException -- error messages and how to fix them
FsMcpConfigException is raised at configuration time (not at runtime) when the server definition is invalid. Every message includes a hint about what to fix:



Message pattern
Cause
Fix




Server name is required...
Missing name in mcpServer { }
Add name "MyServer"


Server version is required...
Missing version in mcpServer { }
Add version "1.0.0"


Invalid server name...
Empty or whitespace-only name
Use a non-empty name string


Duplicate Tool: 'xyz'
Two tools with the same name
Rename one or remove the duplicate


Duplicate Resource: 'uri'
Two resources with the same URI
Use unique URIs


Duplicate Prompt: 'xyz'
Two prompts with the same name
Rename one or remove the duplicate


Tool name is required...
Missing toolName in mcpTool { }
Add toolName "myTool"


Tool handler is required...
Missing handler or typedHandler in mcpTool { }
Add a handler


Cannot add tool: ... already exists
DynamicServer.addTool with duplicate name
Call removeTool first




These exceptions are intentionally raised during configuration (at app startup) so you catch problems immediately, not on the first request.

Client Guide
ClientTransport
ClientTransport is a DU describing how to connect to an MCP server:
type ClientTransport =
    | StdioProcess of command: string * args: string list
    | HttpEndpoint of uri: Uri * headers: Map&lt;string, string&gt;

Use the convenience constructors in the ClientTransport module:
open FsMcp.Client

// Launch a server as a child process over stdio
let stdio = ClientTransport.stdio &quot;dotnet&quot; [ &quot;run&quot;; &quot;--project&quot;; &quot;./MyServer&quot; ]

// Connect to an HTTP server
let http = ClientTransport.http &quot;http://localhost:5000/mcp&quot;

// HTTP with auth headers
let httpAuth =
    ClientTransport.httpWithHeaders
        &quot;http://localhost:5000/mcp&quot;
        (Map.ofList [ &quot;Authorization&quot;, &quot;Bearer my-token&quot; ])

Connecting with McpClient
Create a ClientConfig and call McpClient.connect:
open FsMcp.Core
open FsMcp.Core.Validation
open FsMcp.Client

let config : ClientConfig = {
    Transport = ClientTransport.stdio &quot;dotnet&quot; [ &quot;run&quot;; &quot;--project&quot;; &quot;./MyServer&quot; ]
    Name = &quot;my-client&quot;
    ShutdownTimeout = None
}

// Task-based
task {
    let! client = McpClient.connect config

    // List tools
    let! tools = McpClient.listTools client
    for t in tools do
        printfn $&quot;Tool: {t.Name} -- {t.Description}&quot;

    // Call a tool
    let toolName = ToolName.create &quot;greet&quot; |&gt; unwrapResult
    let args = Map.ofList [
        &quot;name&quot;, System.Text.Json.JsonDocument.Parse(&quot;\&quot;World\&quot;&quot;).RootElement
    ]
    let! result = McpClient.callTool client toolName args
    match result with
    | Ok contents -&gt;
        for c in contents do
            match c with
            | Text t -&gt; printfn $&quot;Result: {t}&quot;
            | _ -&gt; ()
    | Error err -&gt; printfn $&quot;Error: %A{err}&quot;

    // Read a resource
    let uri = ResourceUri.create &quot;info://server/status&quot; |&gt; unwrapResult
    let! resource = McpClient.readResource client uri
    match resource with
    | Ok (TextResource (_, _, text)) -&gt; printfn $&quot;Resource: {text}&quot;
    | Ok (BlobResource _) -&gt; printfn &quot;Got binary resource&quot;
    | Error err -&gt; printfn $&quot;Error: %A{err}&quot;

    // List and get a prompt
    let! prompts = McpClient.listPrompts client
    let promptName = PromptName.create &quot;summarize&quot; |&gt; unwrapResult
    let! promptResult = McpClient.getPrompt client promptName (Map.ofList [ &quot;topic&quot;, &quot;F#&quot; ])
    match promptResult with
    | Ok messages -&gt;
        for m in messages do
            match m.Content with
            | Text t -&gt; printfn $&quot;[{m.Role}] {t}&quot;
            | _ -&gt; ()
    | Error err -&gt; printfn $&quot;Error: %A{err}&quot;

    // Disconnect
    do! McpClient.disconnect client
}

