McpClientAsync module
Every function in McpClient has an Async counterpart in McpClientAsync:
open FsMcp.Client

async {
    let! client = McpClientAsync.connect config
    let! tools = McpClientAsync.listTools client
    let! result = McpClientAsync.callTool client toolName args
    do! McpClientAsync.disconnect client
}

These are thin wrappers that call Async.AwaitTask on the Task-based versions.
ClientPipeline (FsMcp.TaskApi)
The FsMcp.TaskApi package provides pipe-friendly operations for use with taskResult { } from FsToolkit.ErrorHandling. Every operation validates string inputs internally and returns Task&lt;Result&lt;'T, McpError&gt;&gt;:
dotnet add package FsMcp.TaskApi

open FsMcp.Core
open FsMcp.Client
open FsMcp.TaskApi
open FsToolkit.ErrorHandling

let config : ClientConfig = {
    Transport = ClientTransport.stdio &quot;dotnet&quot; [ &quot;run&quot;; &quot;--project&quot;; &quot;./MyServer&quot; ]
    Name = &quot;pipeline-client&quot;
    ShutdownTimeout = None
}

let run () =
    taskResult {
        let! client = ClientPipeline.connect config

        // List tools (Result-wrapped)
        let! tools = ClientPipeline.listTools client

        // Call a tool by string name -- validates name internally
        let args = Map.ofList [
            &quot;name&quot;, System.Text.Json.JsonDocument.Parse(&quot;\&quot;World\&quot;&quot;).RootElement
        ]
        let! contents = client |&gt; ClientPipeline.callTool &quot;greet&quot; args

        // Shortcut: call tool and extract the first text content
        let! text = client |&gt; ClientPipeline.callToolText &quot;greet&quot; args
        printfn $&quot;Got: {text}&quot;

        // Read a resource by string URI
        let! resource = client |&gt; ClientPipeline.readResource &quot;info://server/status&quot;

        // Get a prompt by string name
        let! messages = client |&gt; ClientPipeline.getPrompt &quot;summarize&quot; (Map.ofList [ &quot;topic&quot;, &quot;MCP&quot; ])

        // List resources and prompts
        let! resources = ClientPipeline.listResources client
        let! prompts = ClientPipeline.listPrompts client

        do! client |&gt; ClientPipeline.disconnect
    }

Notice the pipe-friendly argument order: client is the last parameter in callTool, callToolText, readResource, getPrompt, and disconnect, enabling client |&gt; ClientPipeline.callTool "name" args.
Error handling with Result&lt;'T, McpError&gt;
All fallible operations return Result. The McpError DU covers every failure mode:
type McpError =
    | ValidationFailed of errors: ValidationError list
    | ToolNotFound of name: ToolName
    | ResourceNotFound of uri: ResourceUri
    | PromptNotFound of name: PromptName
    | HandlerException of exn: exn
    | TransportError of message: string
    | ProtocolError of code: int * message: string

Pattern match to handle specific errors:
match result with
| Ok contents -&gt; // handle success
| Error (ToolNotFound tn) -&gt;
    printfn $&quot;Tool &#39;{ToolName.value tn}&#39; not found&quot;
| Error (TransportError msg) -&gt;
    printfn $&quot;Transport error: {msg}&quot;
| Error (ProtocolError (code, msg)) -&gt;
    printfn $&quot;Protocol error {code}: {msg}&quot;
| Error (HandlerException ex) -&gt;
    printfn $&quot;Handler threw: {ex.Message}&quot;
| Error (ValidationFailed errors) -&gt;
    for e in errors do
        printfn $&quot;Validation: {ValidationError.format e}&quot;
| Error err -&gt;
    printfn $&quot;Other error: %A{err}&quot;

Testing Guide
FsMcp ships a dedicated testing package that lets you test handlers directly against a ServerConfig without spinning up any transport.
dotnet add package FsMcp.Testing

FsMcp.Testing depends on Expecto and FsCheck.
TestServer -- test handlers without transport
TestServer invokes tool, resource, and prompt handlers by looking them up in the ServerConfig and calling them directly:
TestServer.callTool
open System.Text.Json
open FsMcp.Core
open FsMcp.Server
open FsMcp.Testing

let config = mcpServer {
    name &quot;TestServer&quot;
    version &quot;1.0.0&quot;
    tool (Tool.define &quot;echo&quot; &quot;Echoes input&quot; (fun args -&gt;
        let msg =
            args
            |&gt; Map.tryFind &quot;message&quot;
            |&gt; Option.map (fun j -&gt; j.GetString())
            |&gt; Option.defaultValue &quot;(none)&quot;
        task { return Ok [ Content.text $&quot;Echo: {msg}&quot; ] })
    |&gt; unwrapResult)
    useStdio
}

// Call the tool
let result =
    TestServer.callTool config &quot;echo&quot; (Map.ofList [
        &quot;message&quot;, JsonDocument.Parse(&quot;\&quot;hello\&quot;&quot;).RootElement
    ])
    |&gt; Async.AwaitTask |&gt; Async.RunSynchronously

// result : Result&lt;Content list, McpError&gt;

Returns Error (ToolNotFound tn) if the tool name does not exist in the config.
TestServer.readResource
let result =
    TestServer.readResource config &quot;file:///tmp/test.txt&quot; Map.empty
    |&gt; Async.AwaitTask |&gt; Async.RunSynchronously

// result : Result&lt;ResourceContents, McpError&gt;

Returns Error (ResourceNotFound ru) if the URI is not registered.
TestServer.getPrompt
let result =
    TestServer.getPrompt config &quot;summarize&quot; (Map.ofList [ &quot;topic&quot;, &quot;testing&quot; ])
    |&gt; Async.AwaitTask |&gt; Async.RunSynchronously

// result : Result&lt;McpMessage list, McpError&gt;

Returns Error (PromptNotFound pn) if the prompt name is not registered.
TestServer.listTools, listResources, listPrompts
These return simple info records without invoking any handlers:
let tools : FsMcp.Testing.ToolInfo list = TestServer.listTools config
let resources : FsMcp.Testing.ResourceInfo list = TestServer.listResources config
let prompts : FsMcp.Testing.PromptInfo list = TestServer.listPrompts config

Assertion helpers in Expect
The FsMcp.Testing.Expect module provides MCP-specific assertions that produce clear failure messages:
Expect.mcpIsSuccess
Assert that a Result is Ok and return the inner value:
let contents = Expect.mcpIsSuccess &quot;tool should succeed&quot; result
// contents : Content list

Throws with the McpError details if the result is Error.
Expect.mcpIsError
Assert that a Result is Error and return the McpError:
let err = Expect.mcpIsError &quot;should fail for missing tool&quot; result
// err : McpError

Expect.mcpHasTextContent
Assert that a Result&lt;Content list, McpError&gt; is Ok and contains at least one Text item matching the expected substring:
Expect.mcpHasTextContent &quot;7&quot; &quot;add result&quot; result

This is a convenience that combines mcpIsSuccess + mcpContainsText.
Expect.mcpContainsText
Assert that a Content list contains at least one Text item matching a substring:
let contents = Expect.mcpIsSuccess &quot;should succeed&quot; result
Expect.mcpContainsText &quot;hello&quot; &quot;greeting text&quot; contents

Expect.mcpHasContentCount
Assert the number of content items:
Expect.mcpHasContentCount 1 &quot;single result&quot; contents

